"""A readable parser for standard 5-field cron expressions.

The public entry point is `parse`, which turns a string like
"0 12 * * 1-5" into a CronSchedule. The schedule exposes the concrete set of
matching values for each field plus a describe() method that renders a
human-readable English description.

Organised top-down:
    1. Domain types and field definitions.
    2. Parsing (string -> structured CronSchedule).
    3. Description (structured CronSchedule -> English).
    4. Small, self-contained text helpers.
"""

from __future__ import annotations

import re
from dataclasses import dataclass
from typing import Callable, Optional

# ---------------------------------------------------------------------------
# 1. Domain types and field definitions
# ---------------------------------------------------------------------------


class CronParseError(ValueError):
    """Raised when a cron expression is malformed or out of range."""


@dataclass(frozen=True)
class FieldSpec:
    """Static description of one cron field: its name and allowed bounds."""

    name: str
    min_value: int
    max_value: int


# The five fields, in the order they appear in a cron expression.
FIELD_SPECS: tuple[FieldSpec, ...] = (
    FieldSpec("minute", 0, 59),
    FieldSpec("hour", 0, 23),
    FieldSpec("day_of_month", 1, 31),
    FieldSpec("month", 1, 12),
    FieldSpec("day_of_week", 0, 6),
)


@dataclass(frozen=True)
class CronField:
    """A single parsed field.

    `values` is the authoritative set of matching numbers (used for
    scheduling). `raw` is the original token, kept only so the description
    layer can tell a range (1-5) apart from a list (1,3,5).
    """

    spec: FieldSpec
    raw: str
    values: frozenset[int]

    @property
    def is_wildcard(self) -> bool:
        return self.raw == "*"

    @property
    def is_single(self) -> bool:
        return len(self.values) == 1 and not self.is_wildcard

    @property
    def is_contiguous_range(self) -> bool:
        """True for tokens like 1-5 (a single uninterrupted span)."""
        return "-" in self.raw and "," not in self.raw and "/" not in self.raw

    @property
    def single_value(self) -> int:
        """The lone matching value; only meaningful when is_single."""
        return next(iter(self.values))

    @property
    def wildcard_step(self) -> Optional[int]:
        """The step n for a */n token, or None otherwise."""
        match = re.fullmatch(r"\*/(\d+)", self.raw)
        return int(match.group(1)) if match else None


@dataclass(frozen=True)
class CronSchedule:
    """A fully parsed cron expression."""

    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        """Return a human-readable English description of the schedule."""
        time_clause = _describe_time(self.minute, self.hour)
        day_clause = _describe_days(self.day_of_month, self.month, self.day_of_week)
        return f"{time_clause} {day_clause}".strip()


# ---------------------------------------------------------------------------
# 2. Parsing: string -> CronSchedule
# ---------------------------------------------------------------------------


def parse(expression: str) -> CronSchedule:
    """Parse a 5-field cron expression into a CronSchedule.

    Raises CronParseError for any malformed or out-of-range input.
    """
    tokens = _split_into_fields(expression)
    fields = [_parse_field(token, spec) for token, spec in zip(tokens, FIELD_SPECS)]
    return CronSchedule(*fields)


def _split_into_fields(expression: str) -> list[str]:
    """Split the expression into exactly five whitespace-separated tokens."""
    tokens = expression.split()
    if len(tokens) != len(FIELD_SPECS):
        raise CronParseError(
            f"Expected {len(FIELD_SPECS)} fields but got {len(tokens)}: {expression!r}"
        )
    return tokens


def _parse_field(token: str, spec: FieldSpec) -> CronField:
    """Parse one field token into a CronField.

    A field is a comma-separated list of terms; each term is parsed
    independently and the resulting values are unioned together.
    """
    values: set[int] = set()
    for term in token.split(","):
        values |= _parse_term(term, spec)
    return CronField(spec=spec, raw=token, values=frozenset(values))


def _parse_term(term: str, spec: FieldSpec) -> set[int]:
    """Parse a single term (*, a, a-b, or any of those with /n)."""
    base, step = _split_step(term, spec)
    start, end = _parse_base_range(base, spec)
    return set(range(start, end + 1, step))


def _split_step(term: str, spec: FieldSpec) -> tuple[str, int]:
    """Separate a term into its base and step, e.g. "1-30/5" -> ("1-30", 5)."""
    if "/" not in term:
        return term, 1
    base, _, step_text = term.partition("/")
    step = _to_int(step_text, spec)
    if step <= 0:
        raise CronParseError(f"Step must be positive in field {spec.name!r}: {term!r}")
    return base, step


def _parse_base_range(base: str, spec: FieldSpec) -> tuple[int, int]:
    """Resolve a step's base into an inclusive (start, end) range.

    * covers the whole field, a-b is an explicit range, and a bare a means
    "from a to the field maximum" (so 5/15 starts at 5).
    """
    if base == "*":
        return spec.min_value, spec.max_value
    if "-" in base:
        low_text, _, high_text = base.partition("-")
        return _validate(_to_int(low_text, spec), spec), _validate(_to_int(high_text, spec), spec)
    value = _validate(_to_int(base, spec), spec)
    return value, value


def _to_int(text: str, spec: FieldSpec) -> int:
    """Convert a token to an integer with a clear error on failure."""
    try:
        return int(text)
    except ValueError:
        raise CronParseError(f"Invalid number in field {spec.name!r}: {text!r}") from None


def _validate(value: int, spec: FieldSpec) -> int:
    """Ensure a value falls within the field's allowed bounds."""
    if not spec.min_value <= value <= spec.max_value:
        raise CronParseError(
            f"Value {value} out of range for {spec.name!r} "
            f"({spec.min_value}-{spec.max_value})"
        )
    return value


# ---------------------------------------------------------------------------
# 3. Description: CronSchedule -> English
# ---------------------------------------------------------------------------

WEEKDAY_NAMES: tuple[str, ...] = (
    "Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday",
)
MONTH_NAMES: tuple[str, ...] = (
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
)


def _describe_time(minute: CronField, hour: CronField) -> str:
    """Describe the time-of-day portion (minute + hour)."""
    if minute.is_wildcard and hour.is_wildcard:
        return "Every minute"
    if minute.wildcard_step is not None:
        return f"Every {minute.wildcard_step} minutes"
    if hour.wildcard_step is not None and minute.is_single and minute.single_value == 0:
        return f"Every {hour.wildcard_step} hours, on the hour"
    if minute.is_single and hour.is_single:
        return _format_clock(hour.single_value, minute.single_value)
    if minute.is_single and hour.is_wildcard:
        return f"At {minute.single_value} minutes past every hour"
    return f"At minute {_describe_numbers(minute)} of hour {_describe_numbers(hour)}"


def _format_clock(hour: int, minute: int) -> str:
    """Render a single clock time, e.g. "At 08:30" or "At midnight"."""
    if hour == 0 and minute == 0:
        return "At midnight"
    return f"At {hour:02d}:{minute:02d}"


def _describe_days(
    day_of_month: CronField, month: CronField, day_of_week: CronField
) -> str:
    """Describe the calendar portion (day-of-month, month, day-of-week)."""
    clauses: list[str] = []

    if not day_of_week.is_wildcard:
        clauses.append("on " + _describe_field(day_of_week, _weekday_name))

    if not day_of_month.is_wildcard:
        clauses.append(_describe_month_days(day_of_month, month))
    elif not month.is_wildcard:
        clauses.append("in " + _describe_field(month, _month_name))

    return " and ".join(clauses)


def _describe_month_days(day_of_month: CronField, month: CronField) -> str:
    """Describe day-of-month, scoped to specific months or "every month"."""
    days = _describe_field(day_of_month, _ordinal)
    if month.is_wildcard:
        return f"on the {days} of every month"
    return f"on the {days} of {_describe_field(month, _month_name)}"


def _describe_field(field: CronField, name_of: Callable[[int], str]) -> str:
    """Render a field's values as text using name_of for each value.

    Examples: 1-5 -> "Monday through Friday",
    1,3,5 -> "Monday, Wednesday, and Friday".
    """
    names = [name_of(value) for value in sorted(field.values)]
    if len(names) == 1:
        return names[0]
    if field.is_contiguous_range:
        return f"{names[0]} through {names[-1]}"
    return _join_with_and(names)


def _describe_numbers(field: CronField) -> str:
    """Fallback renderer that lists a field's values as plain numbers."""
    return _describe_field(field, str)


# ---------------------------------------------------------------------------
# 4. Small text helpers
# ---------------------------------------------------------------------------


def _weekday_name(value: int) -> str:
    return WEEKDAY_NAMES[value]


def _month_name(value: int) -> str:
    return MONTH_NAMES[value - 1]


def _ordinal(value: int) -> str:
    """Format a number as an ordinal, e.g. 1 -> "1st", 22 -> "22nd"."""
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")
    return f"{value}{suffix}"


def _join_with_and(items: list[str]) -> str:
    """Join items into an English list with an Oxford comma."""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + ", and " + items[-1]


# ---------------------------------------------------------------------------
# Demo
# ---------------------------------------------------------------------------

if __name__ == "__main__":
    EXAMPLES = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]
    for expression in EXAMPLES:
        print(f"{expression:<16} -> {parse(expression).describe()}")
```

## Design notes

**Decomposition.** The flow is a clean pipeline with one responsibility per function:

- `parse` → `_split_into_fields` → `_parse_field` → `_parse_term` → `_split_step` → `_parse_base_range`
- `describe` → `_describe_time` / `_describe_days` → `_describe_field` → text helpers

**Shared field parsing.** All five fields go through the *same* `_parse_field`/`_parse_term` path — no duplication. Each field only differs by its `FieldSpec` (name + bounds), which also drives validation and error messages.

**Structured result.** `CronSchedule` and `CronField` are frozen dataclasses. `CronField` keeps the authoritative `values` set (what scheduling code would use) separate from the `raw` token (which only the description layer consults, to distinguish `1-5` from `1,3,5`).

**Parse/describe separation.** Parsing produces data; description is pure rendering over that data. The `_describe_field` helper is parameterized by a `name_of` function, so weekdays, months, ordinals, and plain numbers all share one renderer.

**Validation.** `_validate` enforces per-field bounds, `_to_int` gives clear errors on non-numeric tokens, `_split_into_fields` checks the field count, and steps must be positive — all raising `CronParseError` with descriptive messages.

Running it prints exactly the six expected lines (e.g. `0 12 * * 1-5 -> At 12:00 on Monday through Friday`).

