        return len(self.values) == self.max_value - self.min_value + 1

    def is_single_value(self) -> bool:
        return len(self.values) == 1

    def single_value(self) -> int:
        if not self.is_single_value():
            raise ValueError(f"{self.name} does not contain exactly one value")
        return self.values[0]


@dataclass(frozen=True)
class CronSchedule:
    expression: str
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        return describe_schedule(self)


FIELD_SPECS: tuple[FieldSpec, ...] = (
    FieldSpec("minute", 0, 59),
    FieldSpec("hour", 0, 23),
    FieldSpec("day_of_month", 1, 31),
    FieldSpec("month", 1, 12),
    FieldSpec("day_of_week", 0, 6),
)

WEEKDAY_NAMES: Mapping[int, str] = {
    0: "Sunday",
    1: "Monday",
    2: "Tuesday",
    3: "Wednesday",
    4: "Thursday",
    5: "Friday",
    6: "Saturday",
}

MONTH_NAMES: Mapping[int, str] = {
    1: "January",
    2: "February",
    3: "March",
    4: "April",
    5: "May",
    6: "June",
    7: "July",
    8: "August",
    9: "September",
    10: "October",
    11: "November",
    12: "December",
}


def parse_cron(expression: str) -> CronSchedule:
    parts = expression.split()

    if len(parts) != 5:
        raise CronParseError(
            f"Cron expression must have exactly 5 fields; got {len(parts)}: {expression!r}"
        )

    fields = tuple(
        parse_field(text=part, spec=spec)
        for part, spec in zip(parts, FIELD_SPECS)
    )

    return CronSchedule(
        expression=expression,
        minute=fields[0],
        hour=fields[1],
        day_of_month=fields[2],
        month=fields[3],
        day_of_week=fields[4],
    )


def parse_field(text: str, spec: FieldSpec) -> CronField:
    if not text:
        raise CronParseError(f"`{spec.name}` may not be empty")

    items = text.split(",")
    if any(item == "" for item in items):
        raise CronParseError(f"`{spec.name}` contains an empty list item: {text!r}")

    values: set[int] = set()
    for item in items:
        values.update(_parse_field_item(item, spec))

    return CronField(
        name=spec.name,
        source=text,
        min_value=spec.min_value,
        max_value=spec.max_value,
        values=tuple(sorted(values)),
    )


def _parse_field_item(item: str, spec: FieldSpec) -> set[int]:
    base, step = _split_step(item, spec)
    start, end = _parse_base_span(base, spec, has_step=step is not None)
    actual_step = step if step is not None else 1

    return set(range(start, end + 1, actual_step))


def _split_step(item: str, spec: FieldSpec) -> tuple[str, Optional[int]]:
    if item.count("/") > 1:
        raise CronParseError(f"`{spec.name}` has too many step separators: {item!r}")

    if "/" not in item:
        return item, None

    base, step_text = item.split("/", 1)

    if not base:
        raise CronParseError(f"`{spec.name}` step is missing a base range: {item!r}")
    if not step_text:
        raise CronParseError(f"`{spec.name}` step is missing a value: {item!r}")

    step = _parse_step(step_text, spec)
    return base, step


def _parse_base_span(base: str, spec: FieldSpec, has_step: bool) -> tuple[int, int]:
    if base == "*":
        return spec.min_value, spec.max_value

    if base.count("-") > 1:
        raise CronParseError(f"`{spec.name}` has an invalid range: {base!r}")

    if "-" in base:
        start_text, end_text = base.split("-", 1)

        if not start_text or not end_text:
            raise CronParseError(f"`{spec.name}` has an incomplete range: {base!r}")

        start = _parse_value(start_text, spec)
        end = _parse_value(end_text, spec)

        if start > end:
            raise CronParseError(
                f"`{spec.name}` range start must be <= end: {base!r}"
            )

        return start, end

    value = _parse_value(base, spec)

    if has_step:
        return value, spec.max_value

    return value, value


def _parse_value(text: str, spec: FieldSpec) -> int:
    if not text.isdigit():
        raise CronParseError(f"`{spec.name}` value must be an integer: {text!r}")

    value = int(text)

    if value < spec.min_value or value > spec.max_value:
        raise CronParseError(
            f"`{spec.name}` value {value} is outside allowed range "
            f"{spec.min_value}-{spec.max_value}"
        )

    return value


def _parse_step(text: str, spec: FieldSpec) -> int:
    if not text.isdigit():
        raise CronParseError(f"`{spec.name}` step must be an integer: {text!r}")

    step = int(text)

    if step <= 0:
        raise CronParseError(f"`{spec.name}` step must be greater than zero: {text!r}")

    return step


def describe_schedule(schedule: CronSchedule) -> str:
    time_description = _describe_time(schedule.minute, schedule.hour)
    date_clauses = _describe_date(
        schedule.day_of_month,
        schedule.month,
        schedule.day_of_week,
    )

    if not date_clauses:
        return time_description

    return f"{time_description} {' '.join(date_clauses)}"


def _describe_time(minute: CronField, hour: CronField) -> str:
    if minute.is_wildcard() and hour.is_wildcard():
        return "Every minute"

    minute_step = _step_from_minimum(minute)
    if hour.is_wildcard() and minute_step is not None and minute_step > 1:
        return f"Every {minute_step} minutes"

    hour_step = _step_from_minimum(hour)
    if minute.is_single_value() and hour_step is not None and hour_step > 1:
        return _describe_repeating_hours(hour_step, minute.single_value())

    if minute.is_single_value() and hour.is_single_value():
        return _describe_exact_time(hour.single_value(), minute.single_value())

    if hour.is_wildcard() and minute.is_single_value():
        return _describe_hourly_at_minute(minute.single_value())

    if minute.is_wildcard() and hour.is_single_value():
        return f"Every minute during the {hour.single_value():02d}:00 hour"

    if hour.is_wildcard():
        return f"At minutes {_format_numbers(minute.values)} past every hour"

    if minute.is_single_value():
        return _describe_minute_during_hours(minute.single_value(), hour.values)

    return (
        f"At minutes {_format_numbers(minute.values)} "
        f"past hours {_format_numbers(hour.values)}"
    )


def _describe_exact_time(hour: int, minute: int) -> str:
    if hour == 0 and minute == 0:
        return "At midnight"

    return f"At {hour:02d}:{minute:02d}"


def _describe_repeating_hours(hour_step: int, minute: int) -> str:
    if minute == 0:
        return f"Every {hour_step} hours, on the hour"

    minute_word = "minute" if minute == 1 else "minutes"
    return f"Every {hour_step} hours, at {minute} {minute_word} past the hour"


def _describe_hourly_at_minute(minute: int) -> str:
    if minute == 0:
        return "Every hour, on the hour"

    minute_word = "minute" if minute == 1 else "minutes"
    return f"At {minute} {minute_word} past every hour"


def _describe_minute_during_hours(minute: int, hours: Sequence[int]) -> str:
    if minute == 0:
        return f"On the hour during hours {_format_numbers(hours)}"

    minute_word = "minute" if minute == 1 else "minutes"
    return f"At {minute} {minute_word} past hours {_format_numbers(hours)}"


def _describe_date(
    day_of_month: CronField,
    month: CronField,
    day_of_week: CronField,
) -> list[str]:
    clauses: list[str] = []

    if not day_of_month.is_wildcard():
        day_text = _format_ordinals(day_of_month.values)

        if month.is_wildcard():
            clauses.append(f"on the {day_text} of every month")
        else:
            clauses.append(f"on the {day_text}")

    if not month.is_wildcard():
        clauses.append(f"in {_format_named_values(month.values, MONTH_NAMES)}")

    if not day_of_week.is_wildcard():
        clauses.append(f"on {_format_named_values(day_of_week.values, WEEKDAY_NAMES)}")

    return clauses


def _step_from_minimum(field: CronField) -> Optional[int]:
    values = field.values

    if not values or values[0] != field.min_value:
        return None

    if len(values) < 2:
        return None

    step = values[1] - values[0]
    expected = tuple(range(field.min_value, field.max_value + 1, step))

    if values == expected:
        return step

    return None


def _format_named_values(values: Sequence[int], names: Mapping[int, str]) -> str:
    if _is_contiguous(values) and len(values) > 1:
        return f"{names[values[0]]} through {names[values[-1]]}"

    return _join_words([names[value] for value in values])


def _format_numbers(values: Sequence[int]) -> str:
    if _is_contiguous(values) and len(values) > 1:
        return f"{values[0]} through {values[-1]}"

    return _join_words([str(value) for value in values])


def _format_ordinals(values: Sequence[int]) -> str:
    if _is_contiguous(values) and len(values) > 1:
        return f"{_ordinal(values[0])} through {_ordinal(values[-1])}"

    return _join_words([_ordinal(value) for value in values])


def _ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


def _is_contiguous(values: Sequence[int]) -> bool:
    if len(values) < 2:
        return False

    return all(current + 1 == next_value for current, next_value in zip(values, values[1:]))


def _join_words(words: Sequence[str]) -> str:
    if not words:
        return ""

    if len(words) == 1:
        return words[0]

    if len(words) == 2:
        return f"{words[0]} and {words[1]}"

    return f"{', '.join(words[:-1])}, and {words[-1]}"
